/* eslint-disable no-unused-vars */
import React, { useState } from 'react';
import PropTypes from 'prop-types';
import Modal from '../Modal';
import useFetchTMDb from '../../hooks/useFetchTMDb';
import './MoviePreview.css';
import './MoviePreviewModal.css';
import './MoviePreviewModalMediaQueries.css';

function MoviePreview({
  movieInfo: {
    id,
    vote_average: voteAverage,
    title,
    backdrop_path: backdropPath,
    overview,
    poster_path: posterPath,
  },
}) {
  const [isModalVisible, setIsModalVisible] = useState(false);
  const [
    data,
    statusMessage,
    isLoading,
    thereIsAnError,
    setOptions,
  ] = useFetchTMDb('movie');

  return (
    <li className="movie-preview" key={id}>
      {isModalVisible && (
        <Modal>
          <div className="movie-detail">
            <button
              className="close-modal-button"
              type="button"
              onClick={() => setIsModalVisible(false)}
            >
              <i className="material-icons">close</i>
            </button>
            <h1 className="movie-detail-title">{title}</h1>
            {backdropPath ? (
              <img
                className="backdrop-image"
                src={`https://image.tmdb.org/t/p/w1280${backdropPath}`}
                alt={`${title}'s Poster`}
              />
            ) : (
              <div className="image-fallback">
                <i className="material-icons">image</i>
              </div>
            )}
            <div className="text-divider">
              <h2>Overview</h2>
            </div>
            <p className="movie-synopsis">{overview}</p>
            {data ? (
              <>
                <div className="genre-tags">
                  {data.genres.map(({ genreId, name }) => (
                    <span className="genre-tag" key={genreId}>
                      <i className="material-icons">lens</i>
                      {name}
                    </span>
                  ))}
                </div>
                {data.status === 'Rumored' && (
                  <span className="movie-status">
                    <i className="material-icons">chat_bubble</i>
                    {data.status}
                  </span>
                )}
                {data.status === 'Planned' && (
                  <span className="movie-status">
                    <i className="material-icons">list_alt</i>
                    {data.status}
                  </span>
                )}
                {data.status === 'In Production' && (
                  <span className="movie-status">
                    <i className="material-icons">movie_creation</i>
                    {data.status}
                  </span>
                )}
                {data.status === 'Post Production' && (
                  <span className="movie-status">
                    <i className="material-icons">movie_filter</i>
                    {data.status}
                  </span>
                )}
                {data.status === 'Released' && (
                  <span className="movie-status">
                    <i className="material-icons">local_movies</i>
                    {data.status}
                  </span>
                )}
                {data.status === 'Canceled' && (
                  <span className="movie-status">
                    <i className="material-icons">cancel</i>
                    {data.status}
                  </span>
                )}
                <span className="movie-status">
                  <i className="material-icons">access_time</i>
                  {data.runtime}
                </span>
              </>
            ) : (
              <i className="material-icons">refresh</i>
            )}
          </div>
        </Modal>
      )}
      {posterPath ? (
        <img
          className="movie-image"
          src={`https://image.tmdb.org/t/p/w342${posterPath}`}
          alt={`${title}'s Poster`}
        />
      ) : (
        <div className="image-fallback">
          <i className="material-icons">image</i>
        </div>
      )}

      <h4 className="movie-title" title={title}>
        {title}
      </h4>
      <div className="movie-specifications">
        <div className="movie-details">
          <i className="material-icons">star</i>
          <span className="movie-rating">
            <strong>{voteAverage}</strong>
            /10
          </span>
        </div>
        <button
          className="info-button"
          type="button"
          title="info"
          onClick={() => {
            if (!data) {
              setOptions([id]);
              setTimeout(() => setIsModalVisible(true), 500);
            } else {
              setIsModalVisible(true);
            }
          }}
        >
          <i className="material-icons">info</i>
        </button>
      </div>
    </li>
  );
}

export default MoviePreview;

MoviePreview.propTypes = {
  movieInfo: PropTypes.shape({
    id: PropTypes.number,
    video: PropTypes.bool.isRequired,
    vote_count: PropTypes.number.isRequired,
    vote_average: PropTypes.number.isRequired,
    title: PropTypes.string.isRequired,
    release_date: PropTypes.string.isRequired,
    original_language: PropTypes.string.isRequired,
    original_title: PropTypes.string.isRequired,
    genre_ids: PropTypes.arrayOf(PropTypes.number).isRequired,
    backdrop_path: PropTypes.string.isRequired,
    adult: PropTypes.bool.isRequired,
    overview: PropTypes.string.isRequired,
    poster_path: PropTypes.string.isRequired,
    popularity: PropTypes.number.isRequired,
    media_type: PropTypes.string.isRequired,
  }).isRequired,
};
